class Solution(object):
    def canAliceWin(self, n):
        stones = n
        to_remove = 10
        alice_turn = True
        while stones >= to_remove:
            stones -= to_remove
            to_remove -= 1
            alice_turn = not alice_turn
        return not alice_turn
